20	object SimpleBundleDataView {
21	  class BundleA(val w: Int) extends Bundle {
22	    val foo = UInt(w.W)
23	  }
24	  class BundleB(val w: Int) extends Bundle {
25	    val bar = UInt(w.W)
26	  }
27	  implicit val v1: DataView[BundleA, BundleB] = DataView[BundleA, BundleB](a => new BundleB(a.w), _.foo -> _.bar)
28	  implicit val v2: DataView[BundleB, BundleA] = v1.invert(b => new BundleA(b.w))
29	}
