40	object FlatDecoupledDataView {
41	  class FizzBuzz extends Bundle {
42	    val fizz = UInt(8.W)
43	    val buzz = UInt(8.W)
44	  }
45	  class FlatDecoupled extends Bundle {
46	    val valid = Output(Bool())
47	    val ready = Input(Bool())
48	    val fizz = Output(UInt(8.W))
49	    val buzz = Output(UInt(8.W))
50	  }
51	  implicit val view: DataView[FlatDecoupled, DecoupledIO[FizzBuzz]] = DataView[FlatDecoupled, DecoupledIO[FizzBuzz]](
52	    _ => Decoupled(new FizzBuzz),
53	    _.valid -> _.valid,
54	    _.ready -> _.ready,
55	    _.fizz -> _.bits.fizz,
56	    _.buzz -> _.bits.buzz
57	  )
58	  implicit val view2: DataView[DecoupledIO[FizzBuzz], FlatDecoupled] = view.invert(_ => new FlatDecoupled)
59	}
