61	object ValidExtensions {
62	  implicit def view[T <: Data]: DataView[T, Valid[T]] = DataView[T, Valid[T]](
63	    x => Valid(x.cloneType), // Valid will strip direction with `Output(...)` anyway
64	    _ -> _.bits,
65	    (_, v) => true.B -> v.valid
66	  )
67	}
